# The LLM decides which tools to call and in what order
def answer_question(question: str) -> str by llm(
    tools=[get_weather, search_web]
);

# Additional context injection
glob company_info = "TechCorp, products: CloudDB, SecureAuth";

def support_agent(question: str) -> str by llm(
    incl_info={"company": company_info}
);
sem support_agent = "Answer customer questions about our products.";

# ============================================================

import from jaclang.byllm.lib { Image }

def describe_image(image: Image) -> str by llm;

with entry {
    desc = describe_image(Image("photo.jpg"));
    desc = describe_image(Image("https://example.com/img.png"));
}

# Server code (default -- code before any header is server)
node Todo {
    has title: str, done: bool = False;
}

def:pub get_todos() -> list {
    return [{"title": t.title} for t in [root -->][?:Todo]];
}

# The braces bracket exactly the client region.
cl {
    def:pub app() -> JsxElement {
        has items: list = [];

        async can with entry {
            items = await get_todos();
        }

        return <div>
            {[<p key={i.title}>{i.title}</p> for i in items]}
        </div>;
    }
}

# Single-statement form (no block, no braces) -- tags exactly one statement
sv import from .database { connect_db }
cl import from react { useState }

# ============================================================

cl {
    def:pub DataView() -> JsxElement {
        has data: list = [];
        has loading: bool = True;

        # Mount effect (runs once on component mount)
        async can with entry {
            data = await fetch("/api/data").then(
                lambda (r: any) -> any { return r.json(); }
            );
            loading = False;
        }

        # Dependency effect (runs when userId changes)
        # async can with [userId] entry { ... }

        # Multiple dependencies
        # can with (a, b) entry { ... }

        # Cleanup on unmount
        # can with exit { unsubscribe(); }

        if loading { return <p>Loading...</p>; }
        return <div>{data}</div>;
    }
}

# Import server walkers in client code
sv import from ...main { AddTodo, GetTodos }

cl {
    def:pub TodoApp() -> JsxElement {
        has todos: list = [];

        async can with entry {
            result = root spawn GetTodos();
            if result.reports {
                todos = result.reports[0];
            }
        }

        async def add_todo(text: str) -> None {
            result = root spawn AddTodo(title=text);
            if result.reports {
                todos = todos + [result.reports[0]];
            }
        }

        return <div>...</div>;
    }
}

# Server codespace (default)
node Todo {
    has title: str, done: bool = False;
}

def:pub add_todo(title: str) -> dict {
    todo = root ++> Todo(title=title);
    return {"id": jid(todo), "title": todo.title};
}

cl {
    def:pub app -> JsxElement {
        has items: list = [];

        async def add -> None {
            todo = await add_todo("New");
            items = items + [todo];
        }

        return <div>
            <button onClick={lambda -> None { add(); }}>
                Add
            </button>
        </div>;
    }
}
```

The server definitions are visible to the client section. When the client calls `add_todo(...)`, the compiler generates the HTTP call, serialization, and routing between codespaces. You write one language; the compiler produces the interop layer.

Codespaces are similar to namespaces, but instead of organizing names, they organize where code executes. Interop between them -- function calls, spawn calls, type sharing -- is handled by the compiler and runtime.

!!! note "`obj` vs `class` -- choosing the right archetype"
    Cross-codespace interop requires the compiler to fully understand your type's structure. Jac's `obj` is designed for this: it enforces strict, declarative semantics -- fields declared with `has`, auto-generated constructors, no runtime monkey-patching -- so the same definition can compile to Python, JavaScript, or native code.

    If you need Python-specific class features like metaclasses, `@classmethod`, `@property`, or other decorator-heavy patterns, use a regular Python `class`. Those features are inherently tied to the Python runtime and cannot cross codespace boundaries. Jac provides the `static` keyword for static methods and fields, which covers the most common use case.

